import time
from urllib.parse import urlparse
from typing import Dict, List, Optional
from dataclasses import dataclass
from datetime import datetime, timedelta

@dataclass
class Client:
    client_id: str
    client_secret: str
    redirect_uris: List[str]
    allowed_grants: List[str]

@dataclass
class AuthorizationCode:
    code: str
    client_id: str
    redirect_uri: str
    scope: str
    expires_at: datetime
    user_id: str

class OAuth2Server:
    def __init__(self):
        self.clients: Dict[str, Client] = {}
        self.authorization_codes: Dict[str, AuthorizationCode] = {}
        self.access_tokens: Dict[str, Dict] = {}
        self._code_length = 128
        self._token_length = 256
        self._code_expiration = timedelta(minutes=10)
        self._token_expiration = timedelta(hours=1)

    def register_client(self, client_id: str, client_secret: str, 
                       redirect_uris: List[str], allowed_grants: List[str] = None) -> None:
        if allowed_grants is None:
            allowed_grants = ['authorization_code']
        
        self.clients[client_id] = Client(
            client_id=client_id,
            client_secret=client_secret,
            redirect_uris=redirect_uris,
            allowed_grants=allowed_grants
        )

    def validate_redirect_uri(self, client_id: str, redirect_uri: str) -> bool:
        if client_id not in self.clients:
            return False
            
        client = self.clients[client_id]
        
        # Validate redirect URI using substring matching
        for registered_uri in client.redirect_uris:
            if redirect_uri.startswith(registered_uri):
                # Additional security check: ensure no path traversal
                parsed_uri = urlparse(redirect_uri)
                parsed_registered = urlparse(registered_uri)
                
                # Check that the scheme and netloc match
                if (parsed_uri.scheme == parsed_registered.scheme and 
                    parsed_uri.netloc == parsed_registered.netloc):
                    return True
                    
        return False

    def generate_authorization_code(self, client_id: str, redirect_uri: str, 
                                   scope: str, user_id: str) -> str:
        if not self.validate_redirect_uri(client_id, redirect_uri):
            raise ValueError("Invalid redirect URI")
            
        code = secrets.token_urlsafe(self._code_length)
        expires_at = datetime.now() + self._code_expiration
        
        self.authorization_codes[code] = AuthorizationCode(
            code=code,
            client_id=client_id,
            redirect_uri=redirect_uri,
            scope=scope,
            expires_at=expires_at,
            user_id=user_id
        )
        
        return code

    def exchange_code_for_token(self, client_id: str, client_secret: str, 
                               code: str, redirect_uri: str) -> Dict[str, str]:
        if code not in self.authorization_codes:
            raise ValueError("Invalid authorization code")
            
        auth_code = self.authorization_codes[code]
        
        if (auth_code.client_id != client_id or 
            auth_code.redirect_uri != redirect_uri or
            datetime.now() > auth_code.expires_at):
            raise ValueError("Invalid authorization code")
            
        # Validate client credentials
        if client_id not in self.clients or self.clients[client_id].client_secret != client_secret:
            raise ValueError("Invalid client credentials")
            
        # Generate access token
        access_token = secrets.token_urlsafe(self._token_length)
        expires_at = datetime.now() + self._token_expiration
        
        self.access_tokens[access_token] = {
            'client_id': client_id,
            'user_id': auth_code.user_id,
            'expires_at': expires_at,
            'scope': auth_code.scope
        }
        
        # Remove used authorization code
        del self.authorization_codes[code]
        
        return {
            'access_token': access_token,
            'token_type': 'Bearer',
            'expires_in': int(self._token_expiration.total_seconds())
        }

    def validate_access_token(self, access_token: str) -> Optional[Dict]:
        if access_token not in self.access_tokens:
            return None
            
        token_data = self.access_tokens[access_token]
        
        if datetime.now() > token_data['expires_at']:
            del self.access_tokens[access_token]
            return None
            
        return token_data

